// 监听玩家消息发送完成事件
eventOn(tavern_events.MESSAGE_SENT, async function(message_id) {
  console.log('[LocationAppender] MESSAGE_SENT 事件触发, message_id:', message_id);
  try {
    // 获取对应楼层消息
    const messages = getChatMessages(message_id);
    console.log('[LocationAppender] 获取到的消息对象:', messages);
    if (messages.length === 0) {
      console.warn('[LocationAppender] 未找到对应楼层消息');
      return;
    }

    const message = messages[0];
    // 仅处理玩家(user)消息
    if (message.role !== 'user') {
      console.log('[LocationAppender] 非 user 消息, 跳过');
      return;
    }

    // 获取变量表并提取当前位置
    const variables = getVariables();
    console.log('[LocationAppender] 当前变量表快照:', variables);
    const currentPos = _.get(variables, ['stat_data', '环境', '当前位置']);
    console.log('[LocationAppender] 当前位置:', currentPos);

    if (!currentPos) {
      console.warn('[LocationAppender] 未获取到当前位置, 跳过附加');
      return;
    }

    const locationText = `\n\n当前位置: ${currentPos}`;
    // 防止重复添加
    if (message.message.endsWith(locationText)) {
      console.log('[LocationAppender] 消息已包含位置信息, 不重复添加');
      return;
    }

    const updatedMessage = message.message + locationText;
    console.log('[LocationAppender] 更新后的消息内容:', updatedMessage);

    // 更新消息内容
    await setChatMessages([
      {
        message_id: message_id,
        message: updatedMessage,
      },
    ]);
    console.log('[LocationAppender] 已成功在玩家消息末尾添加位置信息');
  } catch (error) {
    console.error('[LocationAppender] 添加位置信息时出错:', error);
  }
});

// 初始化提示
console.log('玩家位置自动附加脚本已加载');

