// Tự động tìm key tiếng Việt, nếu không thấy thì tìm key tiếng Trung tương ứng
function smartGet(obj, viKey) {
    if (!obj) return undefined;
    // 1. Tìm trực tiếp bằng key tiếng Việt
    if (obj[viKey] !== undefined) return obj[viKey];

    // 2. Tìm bằng key tiếng Trung (nếu có trong map)
    const cnKey = DATA_MAPPING[viKey];
    if (cnKey && obj[cnKey] !== undefined) return obj[cnKey];

    // 3. (Phòng hờ) Nếu obj chỉ có key tiếng Trung và viKey không có trong map (ít xảy ra nếu map đủ)
    if (obj[viKey] !== undefined) return obj[viKey];

    return undefined;
}

