// --- HELPER FUNCTIONS ---
function normalizeValue(value) {
  if (Array.isArray(value)) {
    const flattened = [];
    value.forEach((item) => {
      if (Array.isArray(item)) {
        const inner = normalizeValue(item);
        if (Array.isArray(inner)) {
          flattened.push(...inner);
        } else if (inner !== '' && inner !== undefined && inner !== null) {
          flattened.push(inner);
        }
      } else if (item !== undefined && item !== null && item !== '') {
        flattened.push(item);
      }
    });
    if (flattened.length === 0) return '';
    if (flattened.length === 1) return normalizeValue(flattened[0]);
    return flattened;
  }
  return value;
}

function e(value, parse = true) {
  if (value == null) return '';
  const normalized = normalizeValue(value);
  if (Array.isArray(normalized)) {
    const processed = normalized.map((item) => e(item, parse)).filter((item) => item !== '' && item !== undefined && item !== null);
    if (processed.length === 0) return parse ? '' : [];
    return parse ? processed.join(' / ') : processed;
  }
  if (typeof normalized === 'string' && normalized.includes('->')) {
    const match = normalized.match(/(.+)->(.+)\((.+)\)/);
    if (match) {
      const label = match[2].trim();
      return parse ? a(label) : label;
    }
  }
  return parse ? a(normalized) : normalized;
}

function a(value) {
  if (typeof value === 'number') return value;
  if (typeof value === 'string') {
    const cleaned = value.replace(/,/g, '');
    const parsed = parseFloat(cleaned);
    if (!Number.isNaN(parsed)) return parsed;
  }
  return value;
}

function isMetaOnlyObject(value) {
  return (value && typeof value === 'object' && !Array.isArray(value) && '$meta' in value && Object.keys(value).length === 1);
}

function textify(value, fallback = '') {
  const raw = e(value, false);
  if (Array.isArray(raw)) {
    const list = raw.map((item) => textify(item, '')).filter(Boolean);
    return list.length > 0 ? list.join(' / ') : fallback;
  }
  if (raw == null) return fallback;
  return String(raw).trim() || fallback;
}

function toEntries(source) {
  if (source == null) return [];
  const raw = e(source, false);
  if (Array.isArray(raw)) {
    const result = [];
    raw.forEach((item, index) => {
      if (item == null) return;
      if (Array.isArray(item)) {
        item.forEach((nested, nestedIndex) => {
          if (nested == null || isMetaOnlyObject(nested)) return;
          result.push([`${index}-${nestedIndex}`, nested]);
        });
        return;
      }
      if (isMetaOnlyObject(item)) return;
      result.push([String(index), item]);
    });
    return result;
  }
  if (typeof raw === 'object') {
    return Object.entries(raw).filter(([key, value]) => {
      if (key === '$meta' || isMetaOnlyObject(value)) return false;
      return value != null;
    });
  }
  return [['0', raw]];
}

function firstMeaningfulObject(source) {
  if (source && typeof source === 'object' && !Array.isArray(source)) {
    const clone = { ...source };
    delete clone.$meta;
    if (Object.keys(clone).length > 0) return clone;
  }
  const entries = toEntries(source);
  for (const [, value] of entries) {
    if (value && typeof value === 'object' && !Array.isArray(value)) {
      const clone = { ...value };
      delete clone.$meta;
      return clone;
    }
  }
  return {};
}

