function i(equipmentSource, itemsSource, currentWeight, weightLimit) {
  const modal = $('<div>').addClass('inventory-modal');
  const content = $('<div>').addClass('inventory-modal__content');
  const close = $('<span>').addClass('inventory-modal__close').html('×');
  close.on('click', () => modal.remove());
  const weightContainer = $('<div>').addClass('weight-container');
  const percent = Math.max(0, Math.min(100, weightLimit === 0 ? 0 : (currentWeight / weightLimit) * 100));
  const weightBar = $('<div>').addClass('vertical-progress');
  $('<div>').addClass('vertical-progress__bar').css('height', `${percent}%`).appendTo(weightBar);
  $('<div>').addClass('vertical-progress__label').text('Tải trọng').appendTo(weightBar);
  $('<div>').addClass('vertical-progress__value').text(`${currentWeight}/${weightLimit}kg`).appendTo(weightBar);
  weightContainer.append(weightBar);
  content.append(weightContainer);
  const body = $('<div>').addClass('inventory-content');
  body.append($('<h3>').text('Trang bị'));
  const equipmentList = $('<div>').addClass('inventory-list');
  try {
    const entries = toEntries(equipmentSource);
    if (entries.length === 0) {
      equipmentList.append($('<div>').addClass('inventory-list-item').text('Trống'));
    } else {
      entries.forEach(([key, entry]) => {
        const row = $('<div>').addClass('inventory-list-item');
        if (typeof entry === 'string') {
          $('<div>').addClass('item-name').text(fmt(entry)).appendTo(row);
        } else if (entry && typeof entry === 'object') {
          const name = textify(smartGet(entry, 'Tên') ?? entry.name ?? key, key);
          $('<div>').addClass('item-name').text(fmt(name)).appendTo(row);
          const desc = textify(smartGet(entry, 'Mô_tả') ?? entry.desc, '');
          if (desc) $('<div>').addClass('item-desc').text(desc).appendTo(row);
        }
        equipmentList.append(row);
      });
    }
  } catch (error) {
    equipmentList.append($('<div>').addClass('inventory-list-item').text('Trống'));
  }
  body.append(equipmentList);
  body.append($('<h3>').text('Vật phẩm'));
  const itemsGrid = $('<div>').addClass('inventory-grid');
  try {
    const entries = toEntries(itemsSource);
    if (entries.length === 0) {
      itemsGrid.append($('<div>').addClass('inventory-item').text('Trống'));
    } else {
      let hasItem = false;
      entries.forEach(([key, value]) => {
        let quantity = 0; let weight = 0; let name = key;
        if (value && typeof value === 'object' && !Array.isArray(value)) {
          quantity = Number(e(smartGet(value, 'Số_lượng') ?? 1));
          weight = Number(e(smartGet(value, 'Trọng_lượng') ?? 0));
          name = textify(smartGet(value, 'Tên') ?? value.name ?? key, key);
        } else if (value != null) {
          quantity = 1; name = textify(value, key);
        }
        if (quantity > 0) {
          hasItem = true;
          const cell = $('<div>').addClass('inventory-item');
          $('<div>').addClass('item-name').text(fmt(name)).appendTo(cell);
          $('<div>').addClass('item-quantity').text(`x${quantity}`).appendTo(cell);
          if (weight > 0) $('<div>').addClass('item-weight').text(`${weight}kg`).appendTo(cell);
          itemsGrid.append(cell);
        }
      });
      if (!hasItem) itemsGrid.append($('<div>').addClass('inventory-item').text('Trống'));
    }
  } catch (error) {
    itemsGrid.append($('<div>').addClass('inventory-item').text('Trống'));
  }
  body.append(itemsGrid);
  content.append(body);
  content.append(close);
  modal.append(content);
  $('body').append(modal);
}

