function createStatusEffects(container, data) {
  // Lấy dữ liệu an toàn
  const state = smartGet(data, 'Trạng_thái');
  const source = state ? smartGet(state, 'Trạng_thái_hiện_tại') : null;

  if (source == null) return;
  const collected = [];
  const collect = (value) => {
    if (value == null) return;
    if (Array.isArray(value)) { value.forEach(collect); return; }
    if (typeof value === 'object') { Object.values(value).forEach(collect); return; }
    const text = String(value);
    text.split(/[,，、]+/).map((item) => item.trim()).filter(Boolean).forEach((item) => collected.push(item));
  };
  collect(e(source, false));
  const unique = [...new Set(collected.filter(Boolean))];
  if (unique.length === 0) return;
  const wrapper = $('<div>').addClass('status-effects-container');
  $('<div>').addClass('section__title').text('Trạng thái hiện tại').appendTo(wrapper);
  const list = $('<div>').addClass('status-effects-list');
  unique.forEach((effect) => {
    $('<span>').addClass('status-effect-item').text(fmt(effect)).appendTo(list);
  });
  wrapper.append(list);
  container.append(wrapper);
}

