  });
  wrapper.append(attrCol);
  const skillCol = $('<div>').addClass('skill-col');
  $('<div>').addClass('section__title').text('Kỹ năng').appendTo(skillCol);
  const skills = firstMeaningfulObject(skillsSource);
  const entries = Object.entries(skills).filter(([key]) => key !== '$meta');
  if (entries.length === 0) {
    skillCol.append($('<p>').text('Không có kỹ năng'));
  } else {
    entries.forEach(([name, value]) => {
      if (value && typeof value === 'object') {
        const level = Number(e(smartGet(value, 'Cấp_độ') ?? value.level ?? 0));
        const exp = Number(e(smartGet(value, 'Kinh_nghiệm_hiện_tại') ?? value.exp ?? 0));
        const required = Number(e(smartGet(value, 'Kinh_nghiệm_cần_để_thăng_cấp') ?? value.reqExp ?? 100)) || 1;
        const item = $('<div>').addClass('skill-item');
        $('<div>').addClass('skill-name').text(`${fmt(name)} Lv.${level}`).appendTo(item);
        const progress = $('<div>').addClass('progress');
        $('<div>').addClass('progress__bar').css('width', `${Math.min((exp / required) * 100, 100)}%`).appendTo(progress);
        item.append(progress);
        skillCol.append(item);
      } else {
        const numeric = Number(e(value));
        const item = $('<div>').addClass('skill-item');
        $('<div>').addClass('skill-name').text(fmt(name)).appendTo(item);
        const progress = $('<div>').addClass('progress');
        $('<div>').addClass('progress__bar').css('width', `${Math.min((numeric / 100) * 100, 100)}%`).appendTo(progress);
        $('<div>').addClass('skill-value').text(numeric).appendTo(item);
        item.append(progress);
        skillCol.append(item);
      }
    });
  }
  const talents = firstMeaningfulObject(talentsSource);
  const talentEntries = Object.entries(talents).filter(([key]) => key !== '$meta');
  if (talentEntries.length > 0) {
    const talentsHeader = $('<div>').addClass('section__title').text('Thiên phú');
    skillCol.append(talentsHeader);
    talentEntries.forEach(([name, value]) => {
      const item = $('<div>').addClass('skill-item');
      $('<div>').addClass('skill-name').text(fmt(name)).appendTo(item);
      const desc = typeof value === 'string' ? value : textify(smartGet(value, 'Mô_tả') ?? value?.desc ?? '', '');
      $('<div>').addClass('skill-desc').text(desc || 'Không có mô tả').appendTo(item);
      skillCol.append(item);
    });
  }
  wrapper.append(skillCol);
  target.append(wrapper);
}

function renderKeyValueTree(target, data) {
  const entries = toEntries(data);
  if (!entries || entries.length === 0) return;
  const list = $('<ul>').addClass('section__list');
  entries.forEach(([key, value]) => {
    const li = $('<li>');
    if (value && typeof value === 'object') {
      const row = $('<div>').addClass('item');
      $('<span>').addClass('item__key').text(fmt(key)).appendTo(row);
      li.append(row);
      renderKeyValueTree(li, value);
    } else {
      const row = $('<div>').addClass('item');
      $('<span>').addClass('item__key').text(fmt(key)).appendTo(row);
      $('<span>').addClass('item__value').text(textify(value, '')).appendTo(row);
      li.append(row);
    }
    list.append(li);
  });
  target.append(list);
}

function renderOtherGroup(body, title, source) {
  if (source == null) return;
  const group = $('<div>').addClass('other-group');
  $('<div>').addClass('section__title').text(fmt(title)).appendTo(group);
  const entries = toEntries(source);
  if (!entries || entries.length === 0) {
    group.append($('<div>').addClass('empty-text').text(`Không có ${fmt(title)}`));
    body.append(group);
    return;
  }
  const isObjectOfObjects = entries.some(([, v]) => v && typeof v === 'object' && !Array.isArray(v));
  if (isObjectOfObjects) {
    entries.forEach(([name, detail]) => {
      const card = $('<div>').addClass('other-card');
      $('<div>').addClass('other-card__title').text(fmt(name)).appendTo(card);
      renderKeyValueTree(card, detail);
      group.append(card);
    });
  } else {
    renderKeyValueTree(group, source);
  }
  body.append(group);
}

