// Mermaid Zoom & Drag Logic
let mScale = 1;
let mPanning = false;
let mPointX = 0, mPointY = 0, mStart = {x:0, y:0};

function setupMermaidZoom() {
    const container = document.querySelector('.mermaid-container');
    const svg = container.querySelector('svg');
    if(!svg) return;
    svg.style.transition = 'transform 0.1s ease';
    svg.style.transformOrigin = 'center';

    container.addEventListener('mousedown', function(e) {
        mPanning = true;
        mStart = { x: e.clientX - mPointX, y: e.clientY - mPointY };
        container.style.cursor = 'grabbing';
    });

    window.addEventListener('mouseup', function() {
        mPanning = false;
        if(container) container.style.cursor = 'grab';
    });

    let animationFrameId = null;
    window.addEventListener('mousemove', function(e) {
        if (!mPanning) return;
        e.preventDefault();

        if (animationFrameId) return;

        animationFrameId = requestAnimationFrame(() => {
            mPointX = e.clientX - mStart.x;
            mPointY = e.clientY - mStart.y;
            updateMermaidTransform();
            animationFrameId = null;
        });
    });

    container.addEventListener('wheel', function(e) {
        e.preventDefault();
        const delta = e.deltaY > 0 ? 0.9 : 1.1;
        mScale *= delta;
        mScale = Math.min(Math.max(0.5, mScale), 5);
        updateMermaidTransform();
    });
}

function zoomMermaid(factor) {
    if(factor === null) { mScale = 1; mPointX = 0; mPointY = 0; }
    else { mScale *= factor; }
    updateMermaidTransform();
}

function updateMermaidTransform() {
    const svg = document.querySelector('.mermaid-container svg');
    if(svg) svg.style.transform = `translate(${mPointX}px, ${mPointY}px) scale(${mScale})`;
}

function toggleFullScreen() {
    const el = document.querySelector('.image-viewer-modal__content');
    if (!document.fullscreenElement) {
        el.requestFullscreen().catch(err => {
            console.log(`Error attempting to enable full-screen mode: ${err.message}`);
        });
    } else {
        document.exitFullscreen();
    }
}

