function setupMermaidTooltips() {
    // Remove existing tooltips
    $('.mermaid-tooltip').remove();

    // Create Tooltip Element with Fixed Position
    const tooltip = $('<div>').addClass('mermaid-tooltip');
    // Append to modal content to ensure visibility in fullscreen
    $('.image-viewer-modal__content').append(tooltip);

    // Attach events using text matching because Mermaid IDs are unstable
    Object.keys(MAP_DESCRIPTIONS).forEach(key => {
        // Tìm element chứa text của địa điểm (span bên trong div.nodeLabel)
        const nodes = document.querySelectorAll('.nodeLabel');

        nodes.forEach(span => {
            // Check if span text contains key (using includes because of icons fa:...)
            if (span.textContent.includes(key)) {
                // Find parent node group to attach event
                const nodeContainer = span.closest('.node');

                if (nodeContainer) {
                    nodeContainer.style.cursor = 'help'; // Indicate hoverable

                    nodeContainer.addEventListener('mouseenter', function() {
                        tooltip.text(MAP_DESCRIPTIONS[key]).addClass('visible');
                    });

                    nodeContainer.addEventListener('mousemove', function(e) {
                        // Calculate position relative to the viewport
                        let top = e.clientY + 20;
                        let left = e.clientX + 20;

                        // Boundary checks
                        if (left + 350 > window.innerWidth) left = e.clientX - 360;
                        if (top + 150 > window.innerHeight) top = e.clientY - 100;

                        tooltip.css({
                            top: top + 'px',
                            left: left + 'px'
                        });
                    });

                    nodeContainer.addEventListener('mouseleave', function() {
                        tooltip.removeClass('visible');
                    });
                }
            }
        });
    });
}

