// Lắng nghe sự kiện hoàn thành gửi tin nhắn của người chơi
eventOn(tavern_events.MESSAGE_SENT, async function(message_id) {
  console.log('[LocationAppender] Sự kiện MESSAGE_SENT được kích hoạt, message_id:', message_id);
