    if (messages.length === 0) {
      console.warn('[LocationAppender] Không tìm thấy tin nhắn tầng tương ứng');
      return;
    }

    const message = messages[0];
    // Chỉ xử lý tin nhắn của người chơi (user)
    if (message.role !== 'user') {
      console.log('[LocationAppender] Tin nhắn không phải user, bỏ qua');
